import{_ as p,c as l}from"./app.90a21e26.js";const i={},s=l('<h1 id="_49-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#_49-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1" aria-hidden="true">#</a> 49 \u8BB2\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\u3002</p><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECE\u5168\u5C40\u7684\u89D2\u5EA6\u548C\u4F60\u5206\u4EAB\u4E86\u6D4B\u8BD5\u4EBA\u5458\u5B66\u4E60\u67B6\u6784\u77E5\u8BC6\u7684\u91CD\u8981\u6027\u3001\u5E94\u8BE5\u5B66\u5230\u4EC0\u4E48\u7A0B\u5EA6\uFF0C\u4EE5\u53CA\u600E\u4E48\u5B66\u7684\u95EE\u9898\uFF0C\u5E0C\u671B\u4F60\u53EF\u4EE5\u501F\u6B64\u660E\u767D\u7F51\u7AD9\u67B6\u6784\u7684 why\u3001what\u3001how\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C06\u7AD9\u5728\u6D4B\u8BD5\u4EBA\u5458\u7684\u89C6\u89D2\uFF0C\u901A\u8FC7\u8FD9\u4E2A\u4E13\u680F\u7684\u6700\u540E\u56DB\u7BC7\u6587\u7AE0\uFF0C\u548C\u4F60\u5206\u4EAB\u7F51\u7AD9\u7684\u9AD8\u6027\u80FD\u67B6\u6784\u3001\u9AD8\u53EF\u7528\u67B6\u6784\u3001\u4F38\u7F29\u6027\u67B6\u6784\u4EE5\u53CA\u6269\u5C55\u6027\u67B6\u6784\u3002\u5E0C\u671B\u501F\u6B64\u673A\u4F1A\uFF0C\u53EF\u4EE5\u8BA9\u4F60\u5BF9\u7F51\u7AD9\u7684\u67B6\u6784\u8BBE\u8BA1\u505A\u5230\u5FC3\u4E2D\u6709\u6570\uFF0C\u5728\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u65F6\u53EF\u4EE5\u505A\u5230\u6709\u7684\u653E\u77E2\u3002</p><p>\u4ECA\u5929\u6211\u4EEC\u5C31\u5148\u4ECE\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u7684\u8BBE\u8BA1\u5F00\u59CB\u5427\u3002</p><p>\u6027\u80FD\u662F\u7F51\u7AD9\u7684\u91CD\u8981\u6307\u6807\uFF0C\u5982\u679C\u4E00\u4E2A\u7F51\u7AD9\u7684\u8BBF\u95EE\u901F\u5EA6\u5F88\u6162\uFF0C\u5C31\u4F1A\u76F4\u63A5\u5BFC\u81F4\u5927\u91CF\u7528\u6237\u7684\u6D41\u5931\u3002\u6240\u4EE5\u8BF4\uFF0C\u6027\u80FD\u662F\u8BBE\u8BA1\u7F51\u7AD9\u67B6\u6784\u65F6\u8981\u8003\u8651\u7684\u5173\u952E\u56E0\u7D20\u3002\u4E5F\u56E0\u6B64\uFF0C\u7F51\u7AD9\u7684\u6027\u80FD\u95EE\u9898\u6210\u4E86\u7F51\u7AD9\u67B6\u6784\u5347\u7EA7\u3001\u4F18\u5316\u7684\u5BFC\u706B\u7D22\u3002</p><p>\u76EE\u524D\uFF0C\u4E3A\u4E86\u4F18\u5316\u7F51\u7AD9\u6027\u80FD\uFF0C\u4E1A\u754C\u51FA\u73B0\u4E86\u5F88\u591A\u76F8\u5173\u7684\u67B6\u6784\u6539\u8FDB\u65B9\u6848\u548C\u6280\u672F\u624B\u6BB5\u3002\u800C\u5305\u62EC\u4E86\u8FD9\u4E9B\u5347\u7EA7\u3001\u4F18\u5316\u7F51\u7AD9\u6027\u80FD\u7684\u65B9\u6848\u3001\u6280\u672F\u624B\u6BB5\u5728\u5185\u7684\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\uFF0C\u662F\u4E2A\u5F88\u5927\u7684\u8BDD\u9898\uFF0C\u5355\u5355\u4F9D\u9760\u51E0\u7BC7\u6587\u7AE0\u662F\u5F88\u96BE\u8BB2\u6E05\u695A\u7684\u3002\u6240\u4EE5\uFF0C\u6211\u4ECE\u4E2D\u7CBE\u9009\u4E86\u4E00\u4E9B\u5BF9\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u6BD4\u8F83\u5173\u952E\u7684\u6982\u5FF5\u548C\u6280\u672F\uFF0C\u548C\u4F60\u5C55\u5F00\u4ECA\u5929\u7684\u5206\u4EAB\u3002</p><p>\u5982\u679C\u4F60\u60F3\u4E86\u89E3\u66F4\u7EC6\u8282\u7684\u6280\u672F\u5B9E\u73B0\u7684\u8BDD\uFF0C\u53EF\u4EE5\u53C2\u8003\u6211\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\u63A8\u8350\u7684\u5B66\u4E60\u8D44\u6599\uFF0C\u4E5F\u53EF\u4EE5\u76F4\u63A5\u5728\u7559\u8A00\u533A\u7ED9\u6211\u7559\u8A00\u3002</p><p>\u4ECE\u5168\u5C40\u6765\u770B\uFF0C\u7F51\u7AD9\u7684\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\u5305\u62EC\u4E24\u5927\u90E8\u5206\u5185\u5BB9\uFF1A\u4E00\u662F\u524D\u7AEF\u6027\u80FD\uFF0C\u4E8C\u662F\u540E\u7AEF\u670D\u52A1\u5668\u76F8\u5173\u7684\u6027\u80FD\u4F18\u5316\u548C\u67B6\u6784\u8BBE\u8BA1\u3002</p><p><strong>\u524D\u7AEF\u7684\u9AD8\u6027\u80FD\u67B6\u6784</strong></p><p>\u5173\u4E8E\u4EC0\u4E48\u662F\u524D\u7AEF\u6027\u80FD\uFF0C\u4EE5\u53CA\u5982\u4F55\u8BBE\u8BA1\u9488\u5BF9\u524D\u7AEF\u6027\u80FD\u7684\u6D4B\u8BD5\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u53C2\u8003\u7B2C 31 \u7BC7\u6587\u7AE0\u300A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u524D\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u300B\u4E2D\u7684\u76F8\u5173\u5185\u5BB9\u3002</p><p>\u76F8\u5BF9\u6765\u8BF4\uFF0C<strong>\u524D\u7AEF\u9AD8\u6027\u80FD\u67B6\u6784\u6BD4\u8F83\u76F4\u89C2\u6613\u61C2\uFF0C\u5176\u672C\u8D28\u5C31\u662F\u901A\u8FC7\u5404\u79CD\u6280\u672F\u624B\u6BB5\u53BB\u4F18\u5316\u7528\u6237\u5B9E\u9645\u611F\u53D7\u5230\u7684\u524D\u7AEF\u9875\u9762\u5C55\u73B0\u65F6\u95F4\u3002</strong></p><p>\u76EE\u524D\uFF0C\u4E1A\u5185\u7684\u6807\u51C6\u5B9E\u8DF5\u662F\u6765\u81EA\u4E8E\u96C5\u864E\u524D\u7AEF\u6027\u80FD\u56E2\u961F\u63D0\u51FA\u7684 35 \u6761\u539F\u5219\uFF0C\u6211\u5DF2\u7ECF\u5728\u7B2C 29 \u7BC7\u6587\u7AE0\u300A\u804A\u804A\u6027\u80FD\u6D4B\u8BD5\u7684\u57FA\u672C\u65B9\u6CD5\u4E0E\u5E94\u7528\u9886\u57DF\u300B\u4E2D\uFF0C\u4E3A\u4F60\u89E3\u8BFB\u4E86\u5176\u4E2D\u51E0\u4E2A\u6BD4\u8F83\u5178\u578B\u7684\u89C4\u5219\uFF0C\u4F60\u53EF\u4EE5\u518D\u56DE\u987E\u4E0B\u3002\u540C\u65F6\uFF0C\u4F60\u8FD8\u53EF\u4EE5\u8BBF\u95EE\u96C5\u864E\u7F51\u7AD9\u67E5\u770B\u7ECF\u5178\u7684 35 \u6761\u89C4\u5219\uFF0C\u4EE5\u53CA\u5BF9\u5404\u89C4\u5219\u7684\u8BE6\u7EC6\u89E3\u8BFB\u3002</p><p>\u524D\u7AEF\u7684\u9AD8\u6027\u80FD\u67B6\u6784\u76F8\u5BF9\u4E8E\u540E\u7AEF\u6765\u8BB2\u6BD4\u8F83\u5BB9\u6613\u5B9E\u73B0\uFF0C\u56E0\u4E3A\u524D\u7AEF\u6027\u80FD\u4F18\u5316\u7684\u65B9\u6CD5\u662F\u76F8\u5BF9\u6807\u51C6\u7684\u3002\u800C\u4E14\uFF0C\u76EE\u524D\u7684\u524D\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\uFF0C\u6BD4\u5982\u6211\u5728\u524D\u9762\u6587\u7AE0\u4E2D\u66FE\u7ECF\u4ECB\u7ECD\u8FC7\u7684 WebPageTest \u548C YSlow \u4E4B\u7C7B\u7684\u5DE5\u5177\u7B49\uFF0C\u90FD\u80FD\u7CFB\u7EDF\u6027\u5730\u5206\u6790\u524D\u7AEF\u7684\u6027\u80FD\u95EE\u9898\uFF0C\u5E76\u7ED9\u51FA\u5BF9\u5E94\u7684\u89E3\u51B3\u65B9\u6848\u5EFA\u8BAE\u3002</p><p>\u53EF\u4EE5\u8BF4\uFF0C\u6211\u4EEC\u53EA\u8981\u5728\u9879\u76EE\u5F00\u53D1\u8FC7\u7A0B\u4E2D\uFF0C\u628A\u524D\u7AEF\u6027\u80FD\u4F18\u5316\u7EB3\u5165\u4E86\u6D4B\u8BD5\u8303\u56F4\uFF0C\u90A3\u4E48\u4E00\u822C\u6765\u8BB2\u90FD\u80FD\u83B7\u5F97\u6BD4\u8F83\u7406\u60F3\u7684\u6027\u80FD\u4F18\u5316\u7ED3\u679C\u3002</p><p><strong>\u540E\u7AEF\u670D\u52A1\u5668\u7684\u9AD8\u6027\u80FD\u67B6\u6784</strong></p><p>\u540E\u7AEF\u670D\u52A1\u5668\u7684\u9AD8\u6027\u80FD\u67B6\u6784\uFF0C\u4E1A\u5185\u91C7\u7528\u7684\u6700\u4E3B\u8981\u7684\u6280\u672F\u624B\u6BB5\u662F\u7F13\u5B58\u3002\u540C\u65F6\uFF0C\u96C6\u7FA4\u4E5F\u53EF\u4EE5\u4ECE\u8BA1\u7B97\u80FD\u529B\u7684\u89D2\u5EA6\uFF0C\u63D0\u5347\u540E\u7AEF\u7684\u5904\u7406\u6027\u80FD\u3002</p><p><strong>\u7F13\u5B58</strong></p><p>\u53EF\u4EE5\u8BF4\uFF0C\u5728\u8BA1\u7B97\u673A\u7684\u4E16\u754C\u4E2D\uFF0C\u51E1\u662F\u60F3\u8981\u63D0\u9AD8\u6027\u80FD\u7684\u573A\u5408\u90FD\u4F1A\u4F7F\u7528\u5230\u7F13\u5B58\u7684\u601D\u60F3\u3002\u7F13\u5B58\u662F\u6307\u5C06\u6570\u636E\u5B58\u50A8\u5728\u8BBF\u95EE\u901F\u5EA6\u76F8\u5BF9\u8F83\u5FEB\u7684\u5B58\u50A8\u4ECB\u8D28\u4E2D\uFF0C\u6240\u4EE5\u4ECE\u7F13\u5B58\u4E2D\u8BFB\u53D6\u6570\u636E\u7684\u901F\u5EA6\u66F4\u5FEB\u3002</p><p>\u53E6\u5916\uFF0C\u5982\u679C\u7F13\u5B58\u4E2D\u7684\u6570\u636E\u662F\u7ECF\u8FC7\u590D\u6742\u8BA1\u7B97\u5F97\u5230\u7684\uFF0C\u90A3\u4E48\u518D\u6B21\u4F7F\u7528\u88AB\u7F13\u5B58\u7684\u6570\u636E\u65F6\uFF0C\u5C31\u65E0\u9700\u518D\u91CD\u590D\u8BA1\u7B97\u5373\u53EF\u76F4\u63A5\u4F7F\u7528\u3002\u4ECE\u8FD9\u4E2A\u610F\u4E49\u4E0A\u8BB2\uFF0C\u7F13\u5B58\u8FD8\u5177\u6709\u964D\u4F4E\u540E\u7AEF\u8FD0\u7B97\u8D1F\u8F7D\u7684\u4F5C\u7528\u3002</p><p>\u53EF\u89C1\uFF0C\u7F13\u5B58\u5728\u8F6F\u4EF6\u7CFB\u7EDF\u548C\u7F51\u7AD9\u67B6\u6784\u4E2D\u51E0\u4E4E\u65E0\u5904\u4E0D\u5728\u3002\u5F53\u7136\u4E86\uFF0C\u5728\u7CFB\u7EDF\u548C\u8F6F\u4EF6\u7684\u4E0D\u540C\u7EA7\u522B\u5BF9\u5E94\u6709\u4E0D\u540C\u5C42\u7EA7\u7684\u7F13\u5B58\uFF1A</p><ul><li>\u6D4F\u89C8\u5668\u7EA7\u522B\u7684\u7F13\u5B58\uFF0C\u4F1A\u7528\u6765\u5B58\u50A8\u4E4B\u524D\u5728\u7F51\u7EDC\u4E0A\u4E0B\u8F7D\u8FC7\u7684\u9759\u6001\u8D44\u6E90\uFF1B</li><li>CDN \u672C\u8D28\u4E5F\u662F\u7F13\u5B58\uFF0C\u5C5E\u4E8E\u90E8\u7F72\u5728\u7F51\u7EDC\u670D\u52A1\u4F9B\u5E94\u5546\u673A\u623F\u4E2D\u7684\u7F13\u5B58\uFF1B</li><li>\u53CD\u5411\u4EE3\u7406\u670D\u52A1\u5668\u672C\u8D28\u4E0A\u540C\u6837\u4E5F\u662F\u7F13\u5B58\uFF0C\u5C5E\u4E8E\u7528\u6237\u6570\u636E\u4E2D\u5FC3\u6700\u524D\u7AEF\u7684\u7F13\u5B58\uFF1B</li><li>\u6570\u636E\u5E93\u4E2D\u7684\u201C\u70ED\u70B9\u201D\u6570\u636E\uFF0C\u5728\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u4E2D\u6709\u4E00\u7EA7\u7F13\u5B58\uFF0C\u5728\u7F13\u5B58\u670D\u52A1\u96C6\u7FA4\u4E2D\u6709\u4E8C\u7EA7\u7F13\u5B58\uFF1B</li><li>\u751A\u81F3\u662F\u7528\u4E8E URL \u548C\u670D\u52A1\u5668 IP \u5730\u5740\u8F6C\u6362 DNS \u670D\u52A1\u5668\uFF0C\u4E3A\u4E86\u51CF\u5C11\u91CD\u590D\u67E5\u8BE2\u7684\u6B21\u6570\u4E5F\u91C7\u7528\u4E86\u7F13\u5B58\u3002</li></ul><p>\u542F\u7528\u4E86\u7F13\u5B58\u540E\uFF0C\u5F53\u5E94\u7528\u7A0B\u5E8F\u9700\u8981\u8BFB\u53D6\u6570\u636E\u65F6\uFF0C\u4F1A\u5148\u8BD5\u56FE\u4ECE\u7F13\u5B58\u4E2D\u8BFB\u53D6\uFF1A</p><ul><li>\u5982\u679C\u8BFB\u53D6\u6210\u529F\uFF0C\u6211\u4EEC\u79F0\u4E3A\u7F13\u5B58\u547D\u4E2D\uFF0C\u6B64\u65F6\u5C31\u53EF\u4EE5\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u964D\u4F4E\u8BBF\u95EE\u6570\u636E\u5E93\u7684\u65F6\u95F4\u5F00\u9500\u3002</li><li>\u5982\u679C\u6CA1\u6709\u8BFB\u53D6\u5230\u6570\u636E\u6216\u8005\u7F13\u5B58\u4E2D\u7684\u6570\u636E\u5DF2\u7ECF\u8FC7\u671F\u5931\u6548\uFF0C\u90A3\u4E48\u5E94\u7528\u7A0B\u5E8F\u5C31\u4F1A\u8BBF\u95EE\u6570\u636E\u5E93\u53BB\u83B7\u53D6\u76F8\u5E94\u7684\u6570\u636E\u3002\u83B7\u53D6\u5230\u6570\u636E\u540E\uFF0C\u5728\u628A\u6570\u636E\u8FD4\u56DE\u7ED9\u5E94\u7528\u7A0B\u5E8F\u7684\u540C\u65F6\uFF0C\u8FD8\u4F1A\u628A\u8BE5\u6570\u636E\u5199\u5165\u5230\u7F13\u5B58\u4E2D\uFF0C\u4EE5\u5907\u4E0B\u6B21\u4F7F\u7528\u3002</li></ul><p><strong>\u7F13\u5B58\u4E3B\u8981\u7528\u6765\u5B58\u50A8\u90A3\u4E9B\u76F8\u5BF9\u53D8\u5316\u8F83\u5C11\uFF0C\u5E76\u4E14\u9075\u4ECE\u201C\u4E8C\u516B\u539F\u5219\u201D\u7684\u6570\u636E\u3002\u8FD9\u91CC\u7684\u201C\u4E8C\u516B\u539F\u5219\u201D\u6307\u7684\u662F 80%\u7684\u6570\u636E\u8BBF\u95EE\u4F1A\u96C6\u4E2D\u5728 20%\u7684\u6570\u636E\u4E0A\u3002</strong></p><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5982\u679C\u6211\u4EEC\u5C06\u8FD9 20%\u7684\u6570\u636E\u7F13\u5B58\u8D77\u6765\uFF0C\u90A3\u4E48\u8FD9\u4E9B\u6570\u636E\u5C31\u4F1A\u5177\u6709\u975E\u5E38\u9AD8\u7684\u8BFB\u5199\u6BD4\u3002\u8BFB\u5199\u6BD4\u8D8A\u9AD8\uFF0C\u8BF4\u660E\u7F13\u5B58\u4E2D\u7684\u6570\u636E\u88AB\u4F7F\u7528\u7684\u6B21\u6570\u4E5F\u5C31\u8D8A\u591A\uFF0C\u4ECE\u800C\u8282\u7701\u7684\u6570\u636E\u5E93\u8BBF\u95EE\u4E5F\u5C31\u8D8A\u591A\uFF0C\u7F13\u5B58\u7684\u4F18\u52BF\u4E5F\u5C31\u8D8A\u660E\u663E\u3002</p><p>\u9700\u8981\u7279\u522B\u6CE8\u610F\u7684\u662F\uFF0C<strong>\u7F13\u5B58\u6280\u672F\u5E76\u4E0D\u9002\u7528\u4E8E\u90A3\u4E9B\u9700\u8981\u9891\u7E41\u4FEE\u6539\u7684\u6570\u636E</strong>\u3002\u5BF9\u4E8E\u8FD9\u79CD\u9700\u8981\u9891\u7E41\u4FEE\u6539\u7684\u6570\u636E\u6765\u8BF4\uFF0C\u7ECF\u5E38\u4F1A\u51FA\u73B0\u521A\u521A\u5199\u5165\u7F13\u5B58\u7684\u6570\u636E\u8FD8\u6CA1\u6765\u5F97\u53CA\u88AB\u8BFB\u53D6\u5C31\u5DF2\u7ECF\u5931\u6548\u4E86\u7684\u573A\u666F\u3002\u6240\u4EE5\uFF0C\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u7F13\u5B58\u4E0D\u4EC5\u4E0D\u4F1A\u5E26\u6765\u6027\u80FD\u63D0\u5347\uFF0C\u53CD\u800C\u4F1A\u589E\u52A0\u7CFB\u7EDF\u5F00\u9500\u3002</p><p>\u4ECE\u7406\u8BBA\u4E0A\u6765\u8BB2\uFF0C\u7F13\u5B58\u7684\u4F5C\u7528\u662F\u8F85\u52A9\u63D0\u5347\u6570\u636E\u7684\u8BFB\u53D6\u6027\u80FD\uFF0C\u7F13\u5B58\u6570\u636E\u4E22\u5931\u6216\u8005\u7F13\u5B58\u4E0D\u53EF\u7528\u4E0D\u5E94\u8BE5\u5F71\u54CD\u6574\u4E2A\u7CFB\u7EDF\u7684\u53EF\u7528\u6027\uFF0C\u56E0\u4E3A\u5373\u4F7F\u6CA1\u6709\u4E86\u7F13\u5B58\uFF0C\u6570\u636E\u4F9D\u65E7\u53EF\u4EE5\u4ECE\u6570\u636E\u5E93\u4E2D\u83B7\u5F97\u3002\u4F46\u662F\uFF0C\u73B0\u5728\u7684\u6570\u636E\u5E93\u5DF2\u7ECF\u4E60\u60EF\u4E86\u6709\u7F13\u5B58\u7684\u65E5\u5B50\uFF0C\u5047\u5982\u54EA\u5929\u7F13\u5B58\u7CFB\u7EDF\u5954\u6E83\u4E86\uFF0C\u5C31\u4F1A\u5728\u77ED\u65F6\u95F4\u5185\u6709\u5927\u91CF\u7684\u8BF7\u6C42\u6765\u8BBF\u95EE\u6570\u636E\u5E93\uFF0C\u6570\u636E\u5E93\u5C31\u5F88\u53EF\u80FD\u4F1A\u56E0\u4E3A\u65E0\u6CD5\u627F\u53D7\u8FD9\u6837\u7684\u5E76\u53D1\u538B\u529B\u800C\u5B95\u673A\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6709\u4E9B\u7F51\u7AD9\u4F1A\u4F7F\u7528\u7F13\u5B58\u70ED\u5907\u7B49\u6280\u672F\u624B\u6BB5\u6765\u63D0\u4F9B\u7F13\u5B58\u7684\u9AD8\u53EF\u7528\u6027\uFF0C\u5373\uFF1A\u5F53\u67D0\u53F0\u7F13\u5B58\u670D\u52A1\u5668\u5B95\u673A\u7684\u65F6\u5019\uFF0C\u4F1A\u5C06\u7F13\u5B58\u8BBF\u95EE\u5207\u6362\u5230\u70ED\u5907\u7684\u7F13\u5B58\u670D\u52A1\u5668\u4E0A\u3002</p><p>\u53E6\u5916\uFF0C\u5982\u679C\u4F60\u91C7\u7528\u4E86\u5206\u5E03\u5F0F\u7F13\u5B58\u670D\u52A1\u5668\u96C6\u7FA4\u7684\u8BDD\uFF0C\u90A3\u4E48\u7F13\u5B58\u7684\u6570\u636E\u5C06\u88AB\u5206\u5E03\u5230\u96C6\u7FA4\u4E2D\u7684\u591A\u53F0\u670D\u52A1\u5668\u4E0A\uFF0C\u5F53\u5176\u4E2D\u4E00\u53F0\u670D\u52A1\u5668\u5B95\u673A\u7684\u65F6\u5019\uFF0C\u4E5F\u53EA\u4F1A\u4E22\u5931\u4E00\u90E8\u5206\u7F13\u5B58\u6570\u636E\uFF0C\u6B64\u65F6\u901A\u8FC7\u8BBF\u95EE\u6570\u636E\u5E93\u6765\u91CD\u5EFA\u8FD9\u4E9B\u7F13\u5B58\u6570\u636E\u7684\u5F00\u9500\u5E76\u4E0D\u7B97\u592A\u5927\u3002</p><p>\u76EE\u524D\uFF0C\u5206\u5E03\u5F0F\u7F13\u5B58\u67B6\u6784\u7684\u4E3B\u6D41\u6280\u672F\u65B9\u6848\u6709\u4E24\u79CD\uFF1A</p><ul><li>\u4E00\u79CD\u662F\uFF0C<strong>\u5728\u4F01\u4E1A\u7EA7\u5E94\u7528\u4E2D\u5E7F\u6CDB\u91C7\u7528\u7684 JBoss Cache</strong>\u3002JBoss Cache \u9700\u8981\u5728\u7F13\u5B58\u96C6\u7FA4\u4E2D\u7684\u6BCF\u53F0\u673A\u5668\u4E0A\u540C\u6B65\u6240\u6709\u7F13\u5B58\u7684\u526F\u672C\uFF0C\u5F53\u96C6\u7FA4\u89C4\u6A21\u6BD4\u8F83\u5927\u7684\u65F6\u5019\uFF0C\u540C\u6B65\u4EE3\u4EF7\u4F1A\u5F88\u9AD8\u3002\u800C\u4E14\uFF0C\u591A\u4EFD\u526F\u672C\u4E5F\u4F1A\u9020\u6210\u5B58\u50A8\u8D44\u6E90\u7684\u6D6A\u8D39\u3002\u4F46\u5176\u6700\u5927\u7684\u4F18\u70B9\u662F\u901F\u5EA6\u975E\u5E38\u5FEB\uFF0C\u6240\u4EE5 JBoss Cache \u66F4\u9002\u7528\u4E8E\u4F01\u4E1A\u7EA7\u89C4\u6A21\u4E0D\u662F\u5F88\u5927\u7684\u7F13\u5B58\u96C6\u7FA4\u3002\u8FD9\u79CD\u4F01\u4E1A\u7EA7\u7684\u96C6\u7FA4\u4E00\u822C\u5728\u51E0\u53F0\u5230\u5341\u51E0\u53F0\u670D\u52A1\u5668\u7684\u89C4\u6A21\u3002</li><li>\u53E6\u4E00\u79CD\u662F\uFF0C<strong>\u5728\u4E92\u8054\u7F51\u5E94\u7528\u7684\u4E3B\u6D41 Memcached</strong>\u3002Memcached \u5C5E\u4E8E\u4E92\u4E0D\u901A\u4FE1\u7684\u5206\u5E03\u5F0F\u67B6\u6784\uFF0C\u96C6\u7FA4\u4E2D\u5404\u4E2A\u8282\u70B9\u7F13\u5B58\u7684\u6570\u636E\u90FD\u4E0D\u4E00\u6837\uFF0C\u7F13\u5B58\u4F7F\u7528\u8005\u57FA\u4E8E Hash \u4E00\u81F4\u6027\u7B97\u6CD5\u6765\u5B9A\u4F4D\u5177\u4F53\u7684\u5185\u5BB9\u5230\u5E95\u7F13\u5B58\u5728\u96C6\u7FA4\u4E2D\u7684\u54EA\u4E2A\u8282\u70B9\u3002 \u56E0\u6B64\uFF0CMemcached \u5177\u6709\u7F13\u5B58\u5BB9\u91CF\u5927\uFF0C\u5B58\u50A8\u6548\u7387\u9AD8\uFF0C\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u652F\u6301\u96C6\u7FA4\u7684\u6269\u5C55\uFF0C\u4F46\u662F\u901F\u5EA6\u76F8\u5BF9\u8F83\u6162\u7684\u7279\u70B9\u3002\u8FD9\u4E9B\u7279\u70B9\u51B3\u5B9A\u4E86 Memcached \u975E\u5E38\u9002\u7528\u4E8E\u73B0\u5982\u4ECA\u7684\u4E92\u8054\u7F51\u4EA7\u54C1\u67B6\u6784\uFF0C\u51E0\u4E4E\u6210\u4E3A\u4E86\u7F51\u7AD9\u5206\u5E03\u5F0F\u7F13\u5B58\u67B6\u6784\u7684\u4EE3\u540D\u8BCD\u3002 \u4E92\u8054\u7F51\u4EA7\u54C1\u67B6\u6784\u7684\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u89C4\u6A21\u4E00\u822C\u90FD\u5F88\u5927\uFF0C\u5373\u4F7F\u5C0F\u89C4\u6A21\u7684\u5E94\u7528\u96C6\u7FA4\u4E5F\u6709\u4E0A\u767E\u53F0\u673A\u5668\uFF0C\u89C4\u6A21\u5927\u7684\u8BDD\u53EF\u4EE5\u8FBE\u5230\u4E0A\u4E07\u53F0\uFF0C\u8FD9\u79CD\u67B6\u6784\u4E0B\u7684\u7F13\u5B58\u96C6\u7FA4\u89C4\u6A21\u8981\u6C42\u4E5F\u975E\u5E38\u5927\u3002</li></ul><p>\u901A\u8FC7\u4E0A\u9762\u8FD9\u4E9B\u4E9B\u7F13\u5B58\u7684\u57FA\u7840\u77E5\u8BC6\uFF0C\u518D\u7ED3\u5408\u7740\u4F60\u5728\u5E73\u65F6\u9879\u76EE\u4E2D\u79EF\u7D2F\u7684\u76F8\u5173\u7ECF\u9A8C\uFF0C\u76F8\u4FE1\u4F60\u5DF2\u7ECF\u7406\u89E3\u4E86\u7F13\u5B58\u7684\u539F\u7406\u3002\u90A3\u4E48\uFF0C\u63A5\u4E0B\u6765\u6211\u4EEC\u518D\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89C6\u89D2\u6765\u770B\u770B\uFF0C\u5728\u6267\u884C\u6D4B\u8BD5\u65F6\u9700\u8981\u8003\u8651\u5230\u54EA\u4E9B\u4E0E\u7F13\u5B58\u76F8\u5173\u7684\u6D4B\u8BD5\u573A\u666F\uFF1A</p><ul><li>\u5BF9\u4E8E\u524D\u7AEF\u7684\u6D4B\u8BD5\u573A\u666F\uFF0C\u9700\u8981\u5206\u522B\u8003\u8651\u7F13\u5B58\u547D\u4E2D\u548C\u7F13\u5B58\u4E0D\u547D\u4E2D\u60C5\u51B5\u4E0B\u7684\u9875\u9762\u52A0\u8F7D\u65F6\u95F4\u3002</li><li>\u57FA\u4E8E\u7F13\u5B58\u8FC7\u671F\u6D4B\u8BD5\u7B56\u7565\u7684\u8BBE\u8BA1\uFF0C\u9700\u8981\u8003\u8651\u5230\u5FC5\u987B\u8981\u91CD\u65B0\u83B7\u53D6\u6570\u636E\u7684\u6D4B\u8BD5\u573A\u666F\u3002</li><li>\u9700\u8981\u9488\u5BF9\u53EF\u80FD\u5B58\u5728\u7684\u7F13\u5B58\u201C\u810F\u6570\u636E\u201D\uFF0C\u8FDB\u884C\u6709\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u3002\u7F13\u5B58\u201C\u810F\u6570\u636E\u201D\uFF0C\u662F\u6307\u6570\u636E\u5E93\u4E2D\u7684\u6570\u636E\u5DF2\u7ECF\u66F4\u65B0\uFF0C\u4F46\u662F\u7F13\u5B58\u4E2D\u7684\u6570\u636E\u8FD8\u6CA1\u6765\u5F97\u53CA\u66F4\u65B0\u7684\u573A\u666F\u3002</li><li>\u9700\u8981\u9488\u5BF9\u53EF\u80FD\u7684\u7F13\u5B58\u7A7F\u900F\u8FDB\u884C\u5FC5\u8981\u7684\u6D4B\u8BD5\u3002\u7F13\u5B58\u7A7F\u900F\uFF0C\u662F\u6307\u8BBF\u95EE\u7684\u6570\u636E\u5E76\u4E0D\u5B58\u5728\uFF0C\u6240\u4EE5\u8FD9\u90E8\u5206\u6570\u636E\u6C38\u8FDC\u4E0D\u4F1A\u6709\u88AB\u7F13\u5B58\u7684\u673A\u4F1A\uFF0C\u56E0\u6B64\u6B64\u7C7B\u8BF7\u6C42\u4F1A\u4E00\u76F4\u91CD\u590D\u8BBF\u95EE\u6570\u636E\u5E93\u3002</li><li>\u7CFB\u7EDF\u51B7\u542F\u52A8\u540E\uFF0C\u5728\u7F13\u5B58\u9884\u70ED\u9636\u6BB5\u7684\u6570\u636E\u5E93\u8BBF\u95EE\u538B\u529B\u662F\u5426\u4F1A\u8D85\u8FC7\u6570\u636E\u5E93\u5B9E\u9645\u53EF\u4EE5\u627F\u8F7D\u7684\u538B\u529B\u3002</li><li>\u5BF9\u4E8E\u5206\u5E03\u5F0F\u7F13\u5B58\u96C6\u7FA4\u6765\u8BF4\uFF0C\u7531\u4E8E\u5404\u96C6\u7FA4\u4F7F\u7528\u7684\u7F13\u5B58\u7B97\u6CD5\u4E0D\u540C\uFF0C\u90A3\u4E48\u5982\u679C\u8981\u5728\u7F13\u5B58\u96C6\u7FA4\u4E2D\u589E\u52A0\u66F4\u591A\u8282\u70B9\u8FDB\u884C\u6269\u5BB9\u7684\u8BDD\uFF0C\u6269\u5BB9\u5BF9\u539F\u672C\u5DF2\u7ECF\u7F13\u5B58\u6570\u636E\u7684\u5F71\u54CD\u4E5F\u4F1A\u4E0D\u540C\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u9700\u8981\u9488\u5BF9\u7F13\u5B58\u96C6\u7FA4\u6269\u5BB9\u7684\u573A\u666F\uFF0C\u8FDB\u884C\u5FC5\u8981\u7684\u6D4B\u8BD5\u548C\u6027\u80FD\u8BC4\u4F30\u3002</li></ul><p><strong>\u96C6\u7FA4</strong></p><p>\u96C6\u7FA4\u4E5F\u662F\u63D0\u5347\u7F51\u7AD9\u6027\u80FD\u548C\u5E76\u53D1\u5904\u7406\u80FD\u529B\u7684\u5178\u578B\u67B6\u6784\u8BBE\u8BA1\u65B9\u6CD5\u3002</p><p>\u5F53\u4E00\u53F0\u670D\u52A1\u5668\u4E0D\u8DB3\u4EE5\u6EE1\u8DB3\u65E5\u76CA\u589E\u957F\u7684\u7528\u6237\u6D41\u91CF\u65F6\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u8003\u8651\u4F7F\u7528\u591A\u53F0\u670D\u52A1\u5668\u6765\u7EC4\u6210\u4E00\u4E2A\u96C6\u7FA4\uFF1A\u5916\u90E8\u8BF7\u6C42\u5C06\u7EDF\u4E00\u548C\u8D1F\u8F7D\u5747\u8861\u5668\u6253\u4EA4\u9053\uFF1B\u8D1F\u8F7D\u5747\u8861\u5668\u6839\u636E\u4E0D\u540C\u7684\u8D1F\u8F7D\u8C03\u5EA6\u7B97\u6CD5\uFF0C\u5C06\u8BBF\u95EE\u8BF7\u6C42\u4F20\u9012\u7ED9\u96C6\u7FA4\u4E2D\u7684\u67D0\u53F0\u670D\u52A1\u5668\u5904\u7406\u3002</p><p>\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u5728\u8FD9\u79CD\u6A21\u5F0F\u4E0B\uFF0C\u96C6\u7FA4\u4E2D\u7684\u4EFB\u4F55\u4E00\u53F0\u670D\u52A1\u5668\u5B95\u673A\u90FD\u4E0D\u4F1A\u7ED9\u6574\u4E2A\u7CFB\u7EDF\u5E26\u6765\u660E\u663E\u7684\u5F71\u54CD\u3002\u6B64\u65F6\uFF0C\u6BCF\u53F0\u670D\u52A1\u5668\u7684\u5730\u4F4D\u4E5F\u90FD\u4E0D\u600E\u4E48\u9AD8\uFF0C\u6211\u4EEC\u53EF\u4EE5\u76F4\u63A5\u66FF\u6362\u6389\u51FA\u73B0\u4E86\u95EE\u9898\u7684\u67D0\u53F0\u670D\u52A1\u5668\u3002\u540C\u6837\u5730\uFF0C\u5F53\u9700\u8981\u652F\u6301\u66F4\u5927\u7684\u7CFB\u7EDF\u8D1F\u8F7D\u65F6\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u5728\u96C6\u7FA4\u4E2D\u6DFB\u52A0\u66F4\u591A\u7684\u670D\u52A1\u5668\u3002</p><p>\u8FD9\u65F6\uFF0C\u96C6\u7FA4\u4E2D\u7684\u6BCF\u53F0\u670D\u52A1\u5668\u90FD\u53EF\u4EE5\u88AB\u968F\u65F6\u66FF\u6362\u6216\u8005\u6DD8\u6C70\u6389\uFF0C\u5C31\u50CF\u201C\u7272\u53E3\u201D\u4F3C\u7684\u53EF\u4EE5\u4EFB\u4EBA\u5BB0\u5272\u3002\u6240\u4EE5\uFF0C\u8FD9\u79CD\u6A21\u5F0F\uFF0C\u5C31\u6709\u70B9\u7C7B\u4F3C\u4E8E\u201C\u7272\u53E3\u201D\u6A21\u5F0F\u3002</p><p>\u4E0E\u201C\u7272\u53E3\u201D\u6A21\u5F0F\u5BF9\u5E94\u7684\u662F\u201C\u5BA0\u7269\u201D\u6A21\u5F0F\uFF0C\u6BD4\u5982\u4E00\u4E9B\u4F01\u4E1A\u7EA7\u7684\u5E94\u7528\uFF0C\u5B83\u4EEC\u5F80\u5F80\u4E0D\u901A\u8FC7\u96C6\u7FA4\u6765\u6269\u5C55\u7CFB\u7EDF\u7684\u80FD\u529B\u548C\u63D0\u9AD8\u7CFB\u7EDF\u7684\u6027\u80FD\uFF0C\u800C\u662F\u91C7\u7528\u66F4\u4E3A\u5F3A\u52B2\u7684\u670D\u52A1\u5668\u3002</p><p>\u8FD9\u79CD\u6027\u80FD\u975E\u5E38\u5F3A\u5927\u7684\u5355\u53F0\u670D\u52A1\u5668\uFF0C\u4EF7\u683C\u5F80\u5F80\u5341\u5206\u6602\u8D35\uFF0C\u6240\u4EE5\u901A\u5E38\u90FD\u4F1A\u88AB\u7279\u522B\u5173\u7167\uFF0C\u6BD4\u5982\u7ED9\u5176\u914D\u5907\u6700\u597D\u7684\u673A\u623F\u548C UPS \u7B49\u7B49\u3002\u53E6\u5916\uFF0C\u5927\u5BB6\u90FD\u4E0D\u6562\u5BF9\u8FD9\u6837\u7684\u670D\u52A1\u5668\u6709\u4EFB\u4F55\u5927\u7684\u52A8\u4F5C\uFF0C\u751F\u6015\u628A\u5B83\u4EEC\u641E\u574F\u4E86\u3002\u6B64\u65F6\uFF0C\u8FD9\u4E9B\u4EF7\u683C\u6602\u8D35\u7684\u670D\u52A1\u5668\u66F4\u50CF\u662F\u201C\u5BA0\u7269\u201D\u3002</p><p>\u7EFC\u4E0A\u6240\u8FF0\uFF0C\u73B0\u4ECA\u7684\u4E92\u8054\u7F51\u5E94\u7528\u91C7\u7528\u7684\u90FD\u662F\u201C\u7272\u53E3\u201D\u6A21\u5F0F\u3002\u5728\u8FD9\u79CD\u6A21\u5F0F\u4E0B\uFF0C\u6211\u4EEC\u5728\u5F00\u5C55\u6D4B\u8BD5\u65F6\uFF0C\u76F8\u5E94\u5730\u9700\u8981\u989D\u5916\u5173\u6CE8\u4EE5\u4E0B\u8FD9\u4E9B\u6D4B\u8BD5\u70B9\uFF1A</p><ul><li>\u96C6\u7FA4\u5BB9\u91CF\u6269\u5C55\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u96C6\u7FA4\u4E2D\u52A0\u5165\u65B0\u7684\u8282\u70B9\u540E\uFF0C\u662F\u5426\u4F1A\u5BF9\u539F\u6709\u7684 session \u4EA7\u751F\u5F71\u54CD\u3002</li><li>\u5BF9\u4E8E\u65E0\u72B6\u6001\u5E94\u7528\uFF0C\u662F\u5426\u53EF\u4EE5\u5B9E\u73B0\u7075\u6D3B\u7684\u5B9E\u6548\u8F6C\u79FB\u3002</li><li>\u5BF9\u4E8E\u57FA\u4E8E session \u7684\u6709\u72B6\u6001\u5E94\u7528\uFF0C\u9700\u8981\u6839\u636E\u4E0D\u540C\u7684 session \u673A\u5236\u9A8C\u8BC1\u4F1A\u8BDD\u662F\u5426\u53EF\u4EE5\u6B63\u5E38\u4FDD\u6301\uFF0C\u5373\u4FDD\u8BC1\u540C\u4E00 session \u59CB\u7EC8\u90FD\u6709\u540C\u4E00\u4E2A\u786E\u5B9A\u7684\u8282\u70B9\u5728\u5904\u7406\u3002</li><li>\u5F53\u96C6\u7FA4\u4E2D\u7684\u4E00\u4E2A\u6216\u8005\u591A\u4E2A\u8282\u70B9\u5B95\u673A\u65F6\uFF0C\u5BF9\u5728\u7EBF\u7528\u6237\u7684\u5F71\u54CD\u662F\u5426\u7B26\u5408\u8BBE\u8BA1\u9884\u671F\u3002</li><li>\u5BF9\u4E8E\u65E0\u72B6\u6001\u5E94\u7528\u6765\u8BF4\uFF0C\u7CFB\u7EDF\u541E\u5410\u91CF\u662F\u5426\u80FD\u591F\u968F\u7740\u96C6\u7FA4\u4E2D\u8282\u70B9\u7684\u6570\u91CF\u5448\u7EBF\u6027\u589E\u957F\u3002</li><li>\u8D1F\u8F7D\u5747\u8861\u7B97\u6CD5\u7684\u5B9E\u9645\u6548\u679C\uFF0C\u662F\u5426\u7B26\u5408\u9884\u671F\u3002</li><li>\u9AD8\u5E76\u53D1\u573A\u666F\u4E0B\uFF0C\u96C6\u7FA4\u80FD\u591F\u627F\u8F7D\u7684\u6700\u5927\u5BB9\u91CF\u3002</li></ul><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\uFF0C\u6211\u4EE5\u6D4B\u8BD5\u4EBA\u5458\u7684\u89C6\u89D2\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\u4E2D\uFF0C\u9700\u8981\u91CD\u70B9\u5173\u6CE8\u7684\u70B9\u3002</p><p>\u9996\u5148\uFF0C\u7F51\u7AD9\u7684\u6027\u80FD\uFF0C\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u548C\u7528\u6237\u7684\u4F53\u91CF\u6709\u76F4\u63A5\u5173\u7CFB\u3002\u56E0\u6B64\uFF0C\u5F00\u53D1\u4EBA\u5458\u5728\u8BBE\u8BA1\u7F51\u7AD9\u67B6\u6784\u65F6\uFF0C\u5FC5\u987B\u8981\u91CD\u70B9\u8003\u8651\u4E0E\u6027\u80FD\u76F8\u5173\u7684\u67B6\u6784\u8BBE\u8BA1\u3002\u76F8\u5E94\u5730\uFF0C\u6D4B\u8BD5\u4EBA\u5458\u5728\u6D4B\u8BD5\u7F51\u7AD9\u6027\u80FD\u65F6\uFF0C\u4E5F\u8981\u8003\u8651\u5230\u8FD9\u5176\u4E2D\u7684\u67B6\u6784\u8BBE\u8BA1\u3002</p><p>\u5176\u6B21\uFF0C\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\uFF0C\u4E3B\u8981\u5305\u62EC\u524D\u7AEF\u6027\u80FD\u4F18\u5316\u548C\u540E\u7AEF\u670D\u52A1\u5668\u7684\u6027\u80FD\u8C03\u4F18\u3002\u6240\u4EE5\uFF0C\u6211\u4ECE\u8FD9\u4E24\u4E2A\u65B9\u9762\uFF0C\u548C\u4F60\u5C55\u5F00\u4E86\u4ECA\u5929\u7684\u5206\u4EAB\u3002\u6D4B\u8BD5\u4EBA\u5458\u5728\u7406\u89E3\u4E86\u4E24\u5927\u90E8\u5206\u77E5\u8BC6\u7684\u57FA\u7840\u4E0A\uFF0C\u5728\u8BBE\u8BA1\u5177\u4F53\u7684\u6D4B\u8BD5\u65F6\uFF0C\u8981\u8003\u8651\u5230\u8FD9\u4E9B\u7F51\u7AD9\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\u7684\u65B9\u6848\u3001\u6280\u672F\u624B\u6BB5\uFF0C\u4EE5\u6B64\u5236\u5B9A\u51FA\u9700\u8981\u989D\u5916\u589E\u52A0\u7684\u6D4B\u8BD5\u70B9\uFF0C\u4EE5\u53CA\u5BF9\u5E94\u7684\u6D4B\u8BD5\u65B9\u6CD5\u3002</p><p>\u6700\u540E\uFF0C\u5173\u4E8E\u7F51\u7AD9\u6027\u80FD\u6D4B\u8BD5\u7684\u7406\u8BBA\u4E0E\u65B9\u6CD5\uFF0C\u4F60\u53EF\u4EE5\u53C2\u8003\u6211\u5728\u7B2C 28~34 \u7BC7\u6587\u7AE0\uFF08\u4E5F\u5C31\u662F\u6027\u80FD\u6D4B\u8BD5\u7CFB\u5217\u6587\u7AE0\uFF09\u4E2D\u7684\u76F8\u5173\u5185\u5BB9\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5728\u4F60\u63A5\u89E6\u8FC7\u7684\u9879\u76EE\u4E2D\uFF0C\u90FD\u9047\u5230\u8FC7\u54EA\u4E9B\u7CFB\u7EDF\u5C42\u9762\u7684\u9AD8\u6027\u80FD\u67B6\u6784\u8BBE\u8BA1\u65B9\u6848\uFF1F\u4ECE\u6D4B\u8BD5\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u4F60\u53C8\u4F1A\u8BBE\u8BA1\u600E\u6837\u7684\u6D4B\u8BD5\u573A\u666F\u548C\u7528\u4F8B\uFF1F</p>',50);function o(t,e){return s}var n=p(i,[["render",o],["__file","49.html.vue"]]);export{n as default};
